const input = $input.first().json;
const action = input.action || 'translate_text';

// Fetch API key from template_credentials
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.deepl-translate&cred_key=eq.deepl_api_key&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'DeepL API key not configured. Use add_credential to set it up.' } }];
}

const apiKey = creds[0].cred_value;
const baseUrl = apiKey.endsWith(':fx') ? 'https://api-free.deepl.com' : 'https://api.deepl.com';

if (action === 'translate_text') {
  const text = input.text;
  if (!text) {
    return [{ json: { error: 'Parameter "text" is required.' } }];
  }
  const targetLang = (input.target_lang || 'EN').toUpperCase();
  const sourceLang = input.source_lang ? input.source_lang.toUpperCase() : undefined;

  try {
    const body = {
      text: [text],
      target_lang: targetLang
    };
    if (sourceLang) body.source_lang = sourceLang;

    const data = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/v2/translate',
      headers: {
        'Authorization': 'DeepL-Auth-Key ' + apiKey,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(body)
    });

    const parsed = typeof data === 'string' ? JSON.parse(data) : data;

    if (!parsed.translations || parsed.translations.length === 0) {
      return [{ json: { error: 'No translation returned.' } }];
    }

    const t = parsed.translations[0];
    let result = 'Translation (' + t.detected_source_language + ' -> ' + targetLang + '):\n\n';
    result += t.text;

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'DeepL translation failed: ' + err.message } }];
  }

} else if (action === 'detect_language') {
  const text = input.text;
  if (!text) {
    return [{ json: { error: 'Parameter "text" is required.' } }];
  }

  try {
    // Translate to EN just to get detected_source_language
    const data = await helpers.httpRequest({
      method: 'POST',
      url: baseUrl + '/v2/translate',
      headers: {
        'Authorization': 'DeepL-Auth-Key ' + apiKey,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        text: [text.substring(0, 200)],
        target_lang: 'EN'
      })
    });

    const parsed = typeof data === 'string' ? JSON.parse(data) : data;

    if (!parsed.translations || parsed.translations.length === 0) {
      return [{ json: { error: 'Could not detect language.' } }];
    }

    const langCode = parsed.translations[0].detected_source_language;

    const langNames = {
      'BG': 'Bulgarian', 'CS': 'Czech', 'DA': 'Danish', 'DE': 'German',
      'EL': 'Greek', 'EN': 'English', 'ES': 'Spanish', 'ET': 'Estonian',
      'FI': 'Finnish', 'FR': 'French', 'HU': 'Hungarian', 'ID': 'Indonesian',
      'IT': 'Italian', 'JA': 'Japanese', 'KO': 'Korean', 'LT': 'Lithuanian',
      'LV': 'Latvian', 'NB': 'Norwegian', 'NL': 'Dutch', 'PL': 'Polish',
      'PT': 'Portuguese', 'RO': 'Romanian', 'RU': 'Russian', 'SK': 'Slovak',
      'SL': 'Slovenian', 'SV': 'Swedish', 'TR': 'Turkish', 'UK': 'Ukrainian',
      'ZH': 'Chinese', 'AR': 'Arabic'
    };

    const langName = langNames[langCode] || langCode;
    return [{ json: { result: 'Detected language: ' + langName + ' (' + langCode + ')' } }];
  } catch (err) {
    return [{ json: { error: 'Language detection failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use translate_text or detect_language.' } }];
}
